class Solution {
public:
    int numberOfWays(int n, int x, int y) {
        long long mod = 1e9 + 7;
        long long ans = 1;
        for (int i = 1; i <= n; i++) {
            ans = (ans * (y + i - 1)) % mod;
        }
        return (ans * pow(x, n)) % mod;
    }
private:
    long long pow(long long x, long long n) {
        long long res = 1;
        while (n) {
            if (n & 1) res = res * x % 1e9 + 7;
            x = x * x % 1e9 + 7;
            n >>= 1;
        }
        return res;
    }
};
```

